        self.agentContextBuilder = agentContextBuilder
        self.ministerDecisionProvider = ministerDecisionProvider
        self.rulerDirectiveFactory = rulerDirectiveFactory
        self.selectedUnitId = nil
        self.selectedHex = nil
        self.movementHighlights = []
        self.attackHighlights = []
        self.interactionLog = []
        self.lastCommandMessage = nil
    }

    static func bootstrap() -> AppContainer {
        let dataLoader = DataLoader()
        return AppContainer(
            gameState: dataLoader.loadInitialGameState(),
            commandHandler: RuleEngine(),
            dataLoader: dataLoader
        )
    }

    func submit(_ command: Command) {
        let result = commandHandler.execute(command, in: gameState)
        gameState = result.state
        lastCommandMessage = result.message

        let status = result.succeeded ? "accepted" : "rejected"
        appendInteractionEvent("Command \(status): \(command.displayName). \(result.message)")
        refreshSelectionAfterStateChange()
    }

    func handleBoardTap(_ coord: HexCoord) {
        guard gameState.map.contains(coord) else {
            return
        }

        selectedHex = coord
        appendInteractionEvent("Selected hex \(coord.q),\(coord.r).")

        if let tappedDivision = gameState.division(at: coord) {
            handleDivisionTap(tappedDivision)
            return
        }

        if let division = selectedActionDivision {
            submit(.move(divisionId: division.id, destination: coord))
        } else {
            selectedUnitId = nil
            clearHighlights()
        }
    }

    func holdSelected() {
        guard let division = selectedActionDivision else {
            appendInteractionEvent("Hold rejected: no active allied unit selected.")
            return
        }

        submit(.hold(divisionId: division.id))
    }

    func resupplySelected() {
        guard let division = selectedActionDivision else {
            appendInteractionEvent("Resupply rejected: no active allied unit selected.")
            return
        }

        submit(.resupply(divisionId: division.id))
    }

    func endTurn() {
        submit(.endTurn)
    }

    func runCabinetMeeting() {
        guard let cabinet = gameState.cabinetState.cabinet(for: playerFaction) else {
            appendInteractionEvent("Cabinet meeting rejected: no cabinet configured for \(playerFaction.displayName).")
            return
        }

        var nextState = gameState
        var producedDirectives = 0

        for minister in cabinet.ministers {
            let context = agentContextBuilder.ministerContext(for: minister, state: nextState)
            let envelope = ministerDecisionProvider.decisions(for: minister, context: context)

            for directive in envelope.directives {
                nextState.directiveBoard.submit(directive)
                producedDirectives += 1
                nextState.appendEvent("\(minister.name) proposed: \(directive.title).")
            }
        }

        nextState.directiveBoard.arbitrate(cabinetState: nextState.cabinetState, turn: nextState.turn)
        nextState.directiveBoard.downlinkApprovedDirectives(cabinetState: nextState.cabinetState)
        nextState.appendEvent("Cabinet meeting generated \(producedDirectives) advisory directives.")
        gameState = nextState
        appendInteractionEvent("Cabinet meeting completed for \(playerFaction.displayName).")
