        nextState.directiveBoard.submit(directive)
        nextState.directiveBoard.arbitrate(cabinetState: nextState.cabinetState, turn: nextState.turn)
        nextState.directiveBoard.downlinkApprovedDirectives(cabinetState: nextState.cabinetState)
        nextState.appendEvent("Player issued national directive: \(directive.title).")
        gameState = nextState
        appendInteractionEvent("Strategic directive submitted: \(directive.summary)")
