struct AgentContextBuilder {
    let maxFacts: Int
    let maxActiveDirectives: Int

    init(maxFacts: Int = 8, maxActiveDirectives: Int = 6) {
        self.maxFacts = maxFacts
        self.maxActiveDirectives = maxActiveDirectives
    }

    func nationalContext(for faction: Faction, state: GameState) -> NationalContext {
        let activeDirectiveSummaries = state.directiveBoard
            .approvedDirectives
            .filter { $0.faction == faction }
            .prefix(maxActiveDirectives)
            .map { "\($0.title): \($0.summary)" }

        return NationalContext(
            faction: faction,
            turn: state.turn,
            maxTurns: state.maxTurns,
            victorySummary: victorySummary(state.victoryState),
            ownForces: forceSummary(for: faction, state: state),
            enemyForces: forceSummary(for: faction.opponent, state: state),
            objectives: objectiveSummaries(state: state),
            frontLine: frontLineSummary(for: faction, state: state),
            activeDirectives: Array(activeDirectiveSummaries),
            resourceStatus: "V0.5 placeholder: resources and factories are advisory only.",
            threatSummary: threatSummary(for: faction, state: state)
        )
    }

    func ministerContext(for agent: GameAgent, state: GameState) -> MinisterContext {
        let national = nationalContext(for: agent.faction, state: state)
        return MinisterContext(
            agentId: agent.id,
            role: agent.role,
            nationalContext: national,
            departmentFocus: departmentFocus(for: agent.role),
            facts: Array(departmentFacts(for: agent.role, nationalContext: national).prefix(maxFacts))
        )
    }

    func theaterContext(for faction: Faction, state: GameState) -> TheaterContext {
        let directives = state.directiveBoard
            .theaterDirectives
            .filter { $0.faction == faction }
            .prefix(maxActiveDirectives)
            .map(\.summary)

        return TheaterContext(
            faction: faction,
            turn: state.turn,
            assignedDirectiveSummaries: Array(directives),
            frontLine: frontLineSummary(for: faction, state: state),
            availableDivisions: state.divisions.filter { $0.faction == faction }.map(\.name),
            priorityObjectives: objectiveSummaries(state: state).filter { $0.controller != faction }
        )
    }

    func commanderContext(for agent: GameAgent, state: GameState) -> CommanderContext {
        let assigned = state.divisions.filter { agent.assignedDivisionIds.contains($0.id) }
        let activeDirectives = state.directiveBoard
            .theaterDirectives
            .filter { $0.faction == agent.faction && ($0.targetAgentId == nil || $0.targetAgentId == agent.id) }

        return CommanderContext(
            agentId: agent.id,
            faction: agent.faction,
            turn: state.turn,
            assignedDivisions: assigned,
            nearbyKnownEnemies: nearbyEnemies(for: assigned, faction: agent.faction, state: state),
            activeDirectives: activeDirectives
        )
    }

    func agentContext(
        for agent: GameAgent,
        state: GameState,
        playerDirective: String?
    ) -> AgentContext {
        let assignedIds = Set(agent.assignedDivisionIds)
        let friendlyDivisions = state.divisions
            .filter { $0.faction == agent.faction && (assignedIds.isEmpty || assignedIds.contains($0.id)) }
            .map(divisionSummary)
            .sorted { $0.id < $1.id }
        let enemyDivisions = state.divisions
            .filter { $0.faction == agent.faction.opponent }
            .map(divisionSummary)
            .sorted { $0.id < $1.id }

        return AgentContext(
            agentId: agent.id,
            faction: agent.faction,
            turn: state.turn,
            phase: state.phase,
            personality: agent.personality.prompt,
            visibleTiles: tileSummaries(state: state),
            friendlyDivisions: friendlyDivisions,
            enemyDivisions: enemyDivisions,
            objectives: objectiveSummaries(state: state),
            supplySummary: supplySummary(for: agent.faction, state: state),
            recentEvents: recentEvents(state: state),
            playerDirective: playerDirective
        )
    }

    private func forceSummary(for faction: Faction, state: GameState) -> ForceSummary {
        let divisions = state.divisions.filter { $0.faction == faction }
        let totalHP = divisions.reduce(0) { $0 + $1.hp }
        let totalOrganization = divisions.reduce(0) { $0 + $1.organization }
        let divisor = max(1, divisions.count)

        return ForceSummary(
            faction: faction,
            totalDivisions: divisions.count,
            armorDivisions: divisions.filter(\.isArmor).count,
            artilleryDivisions: divisions.filter(\.isArtillery).count,
            averageHP: totalHP / divisor,
            averageOrganization: totalOrganization / divisor,
            supplied: divisions.filter { $0.supplyState == .supplied }.count,
            lowSupply: divisions.filter { $0.supplyState == .lowSupply }.count,
            encircled: divisions.filter { $0.supplyState == .encircled }.count
        )
    }

    private func objectiveSummaries(state: GameState) -> [ObjectiveSummary] {
        state.map.objectives.map { objective in
            ObjectiveSummary(
                id: objective.id,
                name: objective.name,
                coord: objective.coord,
                controller: state.map.tile(at: objective.coord)?.controller,
                type: objective.type
            )
        }
    }

    private func tileSummaries(state: GameState) -> [TileSummary] {
        state.map.tiles.values
            .sorted {
                if $0.coord.q != $1.coord.q {
                    return $0.coord.q < $1.coord.q
                }
                return $0.coord.r < $1.coord.r
            }
            .map { tile in
                TileSummary(
                    coord: tile.coord,
                    baseTerrain: tile.baseTerrain,
                    hasRoad: tile.hasRoad,
                    controller: tile.controller,
                    cityName: tile.cityName,
                    fortressName: tile.fortressName,
                    isPassable: tile.isPassable,
                    visibility: .visible
                )
            }
    }

    private func divisionSummary(_ division: Division) -> DivisionSummary {
        DivisionSummary(
            id: division.id,
            name: division.name,
            faction: division.faction,
            coord: division.coord,
            hp: division.hp,
            maxHP: division.maxHP,
            organization: division.organization,
            supplyState: division.supplyState,
            hasActed: division.hasActed,
            movement: division.movement,
            range: division.range,
            isArmor: division.isArmor,
            isArtillery: division.isArtillery
        )
    }

    private func supplySummary(for faction: Faction, state: GameState) -> SupplySummary {
        let friendly = state.divisions.filter { $0.faction == faction }
        let enemy = state.divisions.filter { $0.faction == faction.opponent }

        return SupplySummary(
            friendlySupplied: friendly.filter { $0.supplyState == .supplied }.count,
            friendlyLowSupply: friendly.filter { $0.supplyState == .lowSupply }.count,
            friendlyEncircled: friendly.filter { $0.supplyState == .encircled }.count,
            enemySupplied: enemy.filter { $0.supplyState == .supplied }.count,
            enemyLowSupply: enemy.filter { $0.supplyState == .lowSupply }.count,
            enemyEncircled: enemy.filter { $0.supplyState == .encircled }.count
        )
    }

    private func recentEvents(state: GameState) -> [EventSummary] {
        state.eventLog
            .suffix(maxFacts)
            .map { entry in
                EventSummary(
                    turn: entry.turn,
                    faction: entry.faction,
                    phase: entry.phase,
                    message: entry.message
                )
            }
    }

    private func frontLineSummary(for faction: Faction, state: GameState) -> FrontLineSummary {
        var contestedEdges = 0
        var vulnerableObjectives: [String] = []

        for tile in state.map.tiles.values where tile.controller == faction {
            for neighborCoord in tile.coord.neighbors {
                guard let neighbor = state.map.tile(at: neighborCoord), neighbor.controller == faction.opponent else {
                    continue
                }
                contestedEdges += 1
            }
        }

        for objective in state.map.objectives {
            guard let tile = state.map.tile(at: objective.coord), tile.controller == faction else {
                continue
            }

            let hasEnemyNeighbor = objective.coord.neighbors.contains {
                state.map.tile(at: $0)?.controller == faction.opponent
            }
            if hasEnemyNeighbor {
                vulnerableObjectives.append(objective.name)
            }
        }

        return FrontLineSummary(
            faction: faction,
            contestedEdges: contestedEdges,
            friendlyControlledTiles: state.map.tiles.values.filter { $0.controller == faction }.count,
            enemyControlledTiles: state.map.tiles.values.filter { $0.controller == faction.opponent }.count,
            vulnerableObjectives: vulnerableObjectives
        )
    }

    private func nearbyEnemies(for divisions: [Division], faction: Faction, state: GameState) -> [Division] {
        state.divisions
            .filter { enemy in
                enemy.faction == faction.opponent && divisions.contains { $0.coord.distance(to: enemy.coord) <= 4 }
            }
            .prefix(6)
            .map { $0 }
    }

    private func victorySummary(_ victoryState: VictoryState) -> String {
        if let winner = victoryState.winner {
            return "\(winner.displayName) victory: \(victoryState.reason?.rawValue ?? "resolved")."
        }
        return "Victory unresolved."
    }

    private func threatSummary(for faction: Faction, state: GameState) -> String {
        let enemy = forceSummary(for: faction.opponent, state: state)
        if enemy.armorDivisions >= 2 {
            return "Enemy armored concentration detected."
        }
        if enemy.artilleryDivisions > 0 {
            return "Enemy artillery can shape key objectives."
        }
        return "No decisive enemy concentration detected."
    }

    private func departmentFocus(for role: AgentRole) -> String {
        switch role {
        case .armamentsMinister:
            return "Production, factories, equipment losses, and future research priorities."
        case .armyMinister:
            return "Manpower, organization, replacement priorities, training, and command assignments."
        case .foreignMinister:
            return "Diplomatic risks, alliance posture, escalation, and negotiation options."
        case .intelligenceMinister:
            return "Enemy threats, unknowns, weak points, and risk warnings."
        case .ruler:
            return "National strategy and final prioritization."
        case .fieldMarshal:
            return "Theater-level front planning."
        case .armyCommander:
            return "Operational execution with assigned divisions."
        }
    }

    private func departmentFacts(for role: AgentRole, nationalContext: NationalContext) -> [String] {
        switch role {
        case .armamentsMinister:
            return [
                "Own divisions: \(nationalContext.ownForces.totalDivisions).",
                "Average HP: \(nationalContext.ownForces.averageHP).",
                "Armored divisions: \(nationalContext.ownForces.armorDivisions).",
                nationalContext.resourceStatus
            ]
        case .armyMinister:
            return [
                "Average organization: \(nationalContext.ownForces.averageOrganization).",
                "Low supply divisions: \(nationalContext.ownForces.lowSupply).",
                "Encircled divisions: \(nationalContext.ownForces.encircled).",
                "Enemy divisions: \(nationalContext.enemyForces.totalDivisions)."
            ]
        case .foreignMinister:
            return [
                "War remains active.",
                "No v0.5 diplomatic action mutates state.",
                "Objectives contested: \(nationalContext.objectives.filter { $0.controller != nationalContext.faction }.count)."
            ]
        case .intelligenceMinister:
            return [
                nationalContext.threatSummary,
                "Contested front edges: \(nationalContext.frontLine.contestedEdges).",
                "Vulnerable objectives: \(nationalContext.frontLine.vulnerableObjectives.joined(separator: ", "))."
            ]
        default:
            return [
                nationalContext.victorySummary,
                "Active directives: \(nationalContext.activeDirectives.count)."
            ]
        }
    }
}

import Foundation

struct LocalLLMDecisionProvider: DecisionProvider {
    let llmClient: LLMClient
    let promptBuilder: AgentPromptBuilder
    let parser: AgentDecisionParser
    let model: String
    let temperature: Double
    let maxTokens: Int

    init(
        llmClient: LLMClient,
        promptBuilder: AgentPromptBuilder = AgentPromptBuilder(),
        parser: AgentDecisionParser = AgentDecisionParser(),
        model: String = "local-model",
        temperature: Double = 0.2,
        maxTokens: Int = 1200
    ) {
        self.llmClient = llmClient
        self.promptBuilder = promptBuilder
        self.parser = parser
        self.model = model
        self.temperature = temperature
        self.maxTokens = maxTokens
    }

    func decide(context: AgentContext) async throws -> AgentDecisionEnvelope {
        let request = promptBuilder.makeRequest(
            context: context,
            model: model,
            temperature: temperature,
            maxTokens: maxTokens
        )
        let rawJSON = try await llmClient.completeJSON(request: request)
        return try parser.parse(rawJSON, expectedAgentId: context.agentId, expectedTurn: context.turn)
    }
}

import Foundation

enum AgentDecisionParserError: Error, Equatable, LocalizedError {
    case malformedJSON(String)
    case unsupportedSchemaVersion(Int)
    case agentMismatch(expected: String, actual: String)
    case turnMismatch(expected: Int, actual: Int)

    var errorDescription: String? {
        switch self {
        case .malformedJSON(let detail):
            return "Malformed agent decision JSON: \(detail)"
        case .unsupportedSchemaVersion(let version):
            return "Unsupported agent decision schemaVersion \(version)."
        case .agentMismatch(let expected, let actual):
            return "Agent decision agentId mismatch. Expected \(expected), got \(actual)."
        case .turnMismatch(let expected, let actual):
            return "Agent decision turn mismatch. Expected \(expected), got \(actual)."
        }
    }
}

struct AgentDecisionParser {
    let supportedSchemaVersion: Int
    private let decoder: JSONDecoder

    init(supportedSchemaVersion: Int = 1, decoder: JSONDecoder = JSONDecoder()) {
        self.supportedSchemaVersion = supportedSchemaVersion
        self.decoder = decoder
    }

    func parse(
        _ rawJSON: String,
        expectedAgentId: String? = nil,
        expectedTurn: Int? = nil
    ) throws -> AgentDecisionEnvelope {
        guard let data = rawJSON.data(using: .utf8) else {
            throw AgentDecisionParserError.malformedJSON("Input is not valid UTF-8.")
        }

        let envelope: AgentDecisionEnvelope
        do {
            envelope = try decoder.decode(AgentDecisionEnvelope.self, from: data)
        } catch {
            throw AgentDecisionParserError.malformedJSON(error.localizedDescription)
        }

        guard envelope.schemaVersion == supportedSchemaVersion else {
            throw AgentDecisionParserError.unsupportedSchemaVersion(envelope.schemaVersion)
        }

        if let expectedAgentId, envelope.agentId != expectedAgentId {
            throw AgentDecisionParserError.agentMismatch(expected: expectedAgentId, actual: envelope.agentId)
        }

        if let expectedTurn, envelope.turn != expectedTurn {
            throw AgentDecisionParserError.turnMismatch(expected: expectedTurn, actual: envelope.turn)
        }

        return envelope
    }
}

import Foundation

struct MockAIClient: DecisionProvider {
    func decide(context: AgentContext) async throws -> AgentDecisionEnvelope {
        var orders: [AgentOrder] = []
        var reservedDestinations = Set(context.friendlyDivisions.map(\.coord) + context.enemyDivisions.map(\.coord))
        let objective = context.objectives.first { $0.name == "Bastogne" } ?? context.objectives.first

        for division in context.friendlyDivisions.sorted(by: orderPriority) {
            guard !division.hasActed else {
                continue
            }

            if division.supplyState == .lowSupply || division.supplyState == .encircled {
                orders.append(
                    AgentOrder(
                        type: .resupply,
                        divisionId: division.id,
                        to: nil,
                        targetDivisionId: nil,
                        stance: "recover",
                        reason: "Unit is \(division.supplyState.rawValue); recover supply before continuing the attack."
                    )
                )
                continue
            }

            if let attackTarget = bestAttackTarget(for: division, context: context) {
                orders.append(
                    AgentOrder(
                        type: .attack,
                        divisionId: division.id,
                        to: nil,
                        targetDivisionId: attackTarget.id,
                        stance: division.isArtillery ? "fireSupport" : "breakthrough",
                        reason: attackReason(attacker: division, target: attackTarget, context: context)
                    )
                )
                continue
            }

            if let objective,
               let destination = bestMoveDestination(
                for: division,
                toward: objective.coord,
                context: context,
                reservedDestinations: reservedDestinations
               ) {
                reservedDestinations.remove(division.coord)
                reservedDestinations.insert(destination)
                orders.append(
                    AgentOrder(
                        type: .move,
                        divisionId: division.id,
                        to: destination,
                        targetDivisionId: nil,
                        stance: division.isArmor ? "roadAdvance" : "advance",
                        reason: "Advance toward \(objective.name), preferring road movement and open routes."
                    )
                )
                continue
            }

            orders.append(
                AgentOrder(
                    type: .hold,
                    divisionId: division.id,
                    to: nil,
                    targetDivisionId: nil,
                    stance: "hold",
                    reason: "No useful visible move or attack is available."
                )
            )
        }

        return AgentDecisionEnvelope(
            schemaVersion: 1,
            agentId: context.agentId,
            turn: context.turn,
            intent: "Break through toward Bastogne using armor on roads and artillery support.",
            orders: orders
        )
    }

    private func orderPriority(_ lhs: DivisionSummary, _ rhs: DivisionSummary) -> Bool {
        if lhs.isArtillery != rhs.isArtillery {
            return !lhs.isArtillery
        }
        if lhs.isArmor != rhs.isArmor {
            return lhs.isArmor
        }
        return lhs.id < rhs.id
    }

    private func bestAttackTarget(
        for division: DivisionSummary,
        context: AgentContext
    ) -> DivisionSummary? {
        context.enemyDivisions
            .filter { division.coord.distance(to: $0.coord) <= division.range }
            .sorted { lhs, rhs in
                let lhsScore = attackScore(attacker: division, target: lhs, context: context)
                let rhsScore = attackScore(attacker: division, target: rhs, context: context)
                if lhsScore != rhsScore {
                    return lhsScore > rhsScore
                }
                return lhs.hp < rhs.hp
            }
            .first
    }

    private func attackScore(
        attacker: DivisionSummary,
        target: DivisionSummary,
        context: AgentContext
    ) -> Int {
        let targetTile = context.visibleTiles.first { $0.coord == target.coord }
        let objectiveTileBonus = targetTile?.baseTerrain == .city || targetTile?.baseTerrain == .fortress ? 20 : 0
        let lowHPBonus = max(0, 12 - target.hp)
        let distanceBonus = max(0, 4 - attacker.coord.distance(to: target.coord))
        let artilleryBonus = attacker.isArtillery ? objectiveTileBonus : 0
        return lowHPBonus + distanceBonus + artilleryBonus
    }

    private func attackReason(
        attacker: DivisionSummary,
        target: DivisionSummary,
        context: AgentContext
    ) -> String {
        let targetTile = context.visibleTiles.first { $0.coord == target.coord }
        if attacker.isArtillery,
           targetTile?.baseTerrain == .city || targetTile?.baseTerrain == .fortress {
            return "Artillery fires on defender in a city or fortress hex."
        }
        return "Target is within range and vulnerable enough for a local attack."
    }

    private func bestMoveDestination(
        for division: DivisionSummary,
        toward objectiveCoord: HexCoord,
        context: AgentContext,
        reservedDestinations: Set<HexCoord>
    ) -> HexCoord? {
        let currentDistance = division.coord.distance(to: objectiveCoord)
        let tileByCoord = Dictionary(uniqueKeysWithValues: context.visibleTiles.map { ($0.coord, $0) })

        return division.coord.neighbors
            .compactMap { coord -> TileSummary? in
                guard let tile = tileByCoord[coord],
                      tile.isPassable,
                      !reservedDestinations.contains(coord),
                      coord.distance(to: objectiveCoord) <= currentDistance else {
                    return nil
                }
                return tile
            }
            .sorted { lhs, rhs in
                let lhsDistance = lhs.coord.distance(to: objectiveCoord)
                let rhsDistance = rhs.coord.distance(to: objectiveCoord)
                if lhsDistance != rhsDistance {
                    return lhsDistance < rhsDistance
                }
                if lhs.hasRoad != rhs.hasRoad {
                    return lhs.hasRoad
                }
                return terrainMoveCost(lhs.baseTerrain) < terrainMoveCost(rhs.baseTerrain)
            }
            .first?
            .coord
    }

    private func terrainMoveCost(_ terrain: BaseTerrain) -> Int {
        terrain.movementCost
    }
}

import XCTest
@testable import WWIIHexV0

final class AgentPipelineTests: XCTestCase {
    func testAgentContextBuilderCreatesCodableContext() throws {
        let state = Self.testState(activeFaction: .germany)
        let agent = GameAgent.guderianFallback(assignedDivisionIds: ["ger_panzer_1"])
        let context = AgentContextBuilder().agentContext(
            for: agent,
            state: state,
            playerDirective: "Break through toward Bastogne."
        )

        XCTAssertEqual(context.agentId, "guderian")
        XCTAssertEqual(context.friendlyDivisions.map(\.id), ["ger_panzer_1"])
        XCTAssertEqual(context.enemyDivisions.map(\.id), ["all_infantry_1"])
        XCTAssertFalse(context.visibleTiles.isEmpty)
        XCTAssertTrue(context.visibleTiles.allSatisfy { $0.visibility == .visible })

        let data = try JSONEncoder().encode(context)
        let decoded = try JSONDecoder().decode(AgentContext.self, from: data)
        XCTAssertEqual(decoded, context)
    }

    func testMockAIClientOutputsCodableDecisionEnvelope() async throws {
        let state = Self.testState(activeFaction: .germany)
        let agent = GameAgent.guderianFallback(assignedDivisionIds: ["ger_panzer_1"])
        let context = AgentContextBuilder().agentContext(for: agent, state: state, playerDirective: nil)

        let envelope = try await MockAIClient().decide(context: context)

        XCTAssertEqual(envelope.schemaVersion, 1)
        XCTAssertEqual(envelope.agentId, "guderian")
        XCTAssertFalse(envelope.orders.isEmpty)

        let data = try JSONEncoder().encode(envelope)
        let decoded = try JSONDecoder().decode(AgentDecisionEnvelope.self, from: data)
        XCTAssertEqual(decoded, envelope)
    }

    func testParserAcceptsValidMoveJSONAndRejectsBadJSON() throws {
        let json = """
        {
          "schemaVersion": 1,
          "agentId": "guderian",
          "turn": 1,
          "intent": "Advance",
          "orders": [
            {
              "type": "move",
              "divisionId": "ger_panzer_1",
              "to": { "q": 8, "r": 3 },
              "targetDivisionId": null,
              "stance": null,
              "reason": "Move west."
            }
          ]
        }
        """

        let parser = AgentDecisionParser()
        let envelope = try parser.parse(json, expectedAgentId: "guderian", expectedTurn: 1)

        XCTAssertEqual(envelope.orders.first?.type, .move)
        XCTAssertThrowsError(try parser.parse("{bad json", expectedAgentId: "guderian", expectedTurn: 1)) { error in
            XCTAssertTrue(error is AgentDecisionParserError)
        }
    }

    func testParserRejectsMismatchedSchemaAgentAndTurn() {
        let parser = AgentDecisionParser()
        let schemaJSON = """
        {"schemaVersion":2,"agentId":"guderian","turn":1,"intent":"x","orders":[]}
        """
        let agentJSON = """
        {"schemaVersion":1,"agentId":"other","turn":1,"intent":"x","orders":[]}
        """
        let turnJSON = """
        {"schemaVersion":1,"agentId":"guderian","turn":2,"intent":"x","orders":[]}
        """

        XCTAssertThrowsError(try parser.parse(schemaJSON, expectedAgentId: "guderian", expectedTurn: 1))
        XCTAssertThrowsError(try parser.parse(agentJSON, expectedAgentId: "guderian", expectedTurn: 1))
        XCTAssertThrowsError(try parser.parse(turnJSON, expectedAgentId: "guderian", expectedTurn: 1))
    }

    func testAgentOrderMapperMapsMoveAndAttack() throws {
        let mapper = AgentCommandMapper()
        let move = AgentOrder(
            type: .move,
            divisionId: "ger_panzer_1",
            to: HexCoord(q: 8, r: 3),
            targetDivisionId: nil,
            stance: nil,
            reason: "Advance."
        )
        let attack = AgentOrder(
            type: .attack,
            divisionId: "ger_panzer_1",
            to: nil,
            targetDivisionId: "all_infantry_1",
            stance: nil,
            reason: "Attack."
        )

        XCTAssertEqual(
            try mapper.map(move, agentId: "guderian").command,
            .move(divisionId: "ger_panzer_1", destination: HexCoord(q: 8, r: 3))
        )
        XCTAssertEqual(
            try mapper.map(attack, agentId: "guderian").command,
            .attack(attackerId: "ger_panzer_1", targetId: "all_infantry_1")
        )
    }

    func testAgentOrderMapperRejectsMissingRequiredFields() {
        let mapper = AgentCommandMapper()
        let badMove = AgentOrder(
            type: .move,
            divisionId: "ger_panzer_1",
            to: nil,
            targetDivisionId: nil,
            stance: nil,
            reason: "Missing destination."
        )
        let badAttack = AgentOrder(
            type: .attack,
            divisionId: "ger_panzer_1",
            to: nil,
            targetDivisionId: nil,
            stance: nil,
            reason: "Missing target."
        )

        XCTAssertThrowsError(try mapper.map(badMove, agentId: "guderian"))
        XCTAssertThrowsError(try mapper.map(badAttack, agentId: "guderian"))
    }

    func testProviderFailureDoesNotModifyGameState() async {
        let state = Self.testState(activeFaction: .germany)
        let manager = TurnManager(
            agent: GameAgent.guderianFallback(assignedDivisionIds: ["ger_panzer_1"]),
            provider: FailingDecisionProvider(),
            providerName: "FailingProvider",
            commandHandler: RuleEngine()
        )

        let outcome = await manager.runGermanAITurn(state: state)

        XCTAssertEqual(outcome.state, state)
        XCTAssertFalse(outcome.record.errors.isEmpty)
        XCTAssertTrue(outcome.record.commandResults.isEmpty)
    }

    func testInvalidMappedCommandIsRecordedAndDoesNotExecute() async {
        let state = Self.testState(activeFaction: .germany)
        let provider = StaticDecisionProvider(
            envelope: AgentDecisionEnvelope(
                schemaVersion: 1,
                agentId: "guderian",
                turn: 1,
                intent: "Attempt invalid move.",
                orders: [
                    AgentOrder(
                        type: .move,
                        divisionId: "ger_panzer_1",
                        to: HexCoord(q: 99, r: 99),
                        targetDivisionId: nil,
                        stance: nil,
                        reason: "Out of bounds."
                    )
                ]
            )
        )
        let manager = TurnManager(
            agent: GameAgent.guderianFallback(assignedDivisionIds: ["ger_panzer_1"]),
            provider: provider,
            providerName: "Static",
            commandHandler: RuleEngine()
        )

        let outcome = await manager.runGermanAITurn(state: state)

        XCTAssertEqual(outcome.record.commandResults.first?.validationSucceeded, false)
        XCTAssertEqual(outcome.record.commandResults.first?.errors, ["destinationOutOfBounds"])
        XCTAssertEqual(outcome.state.division(id: "ger_panzer_1")?.coord, state.division(id: "ger_panzer_1")?.coord)
        XCTAssertEqual(outcome.state.activeFaction, .allies)
    }

    private static func testState(activeFaction: Faction) -> GameState {
        GameState(
            scenarioId: "agent_test",
            turn: 1,
            maxTurns: 8,
            activeFaction: activeFaction,
            phase: activeFaction == .germany ? .germanAI : .alliedPlayer,
            map: MapState.ardennesV0(),
            divisions: [
                Division.panzer(
                    id: "ger_panzer_1",
                    name: "1st Panzer Division",
                    faction: .germany,
                    coord: HexCoord(q: 9, r: 3)
                ),
                Division.infantry(
                    id: "all_infantry_1",
                    name: "101st Infantry Division",
                    faction: .allies,
                    coord: HexCoord(q: 4, r: 5)
                )
            ],
            victoryState: .ongoing,
            selectedUnitSummary: nil,
            eventLog: [
                GameLogEntry(turn: 1, faction: .germany, phase: .germanAI, message: "Test event.")
            ]
        )
    }
}

private struct StaticDecisionProvider: DecisionProvider {
    let envelope: AgentDecisionEnvelope

    func decide(context: AgentContext) async throws -> AgentDecisionEnvelope {
        envelope
    }
}

private struct FailingDecisionProvider: DecisionProvider {
    func decide(context: AgentContext) async throws -> AgentDecisionEnvelope {
        throw TestProviderError.failed
    }
}

